THOUGHT: Add an early guard in impliesPoisonOrCond to prevent the poison implication for pattern (icmp samesign eq X, negativeC) vs (icmp ne X, 0), then rebuild opt and test the IR to ensure select not folded. (Skipping submit-patch until behavior verified.)

```bash
FN_LINE=$(grep -n "static bool impliesPoisonOrCond" llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp | cut -d: -f1) && \
INSERT_LINE=$((FN_LINE+1)) && \
sed -i "${INSERT_LINE}i\  // PR120361: Prevent folding select B, (icmp samesign eq X, Cneg), false\ 
  // to the potentially poison icmp when B is (icmp ne X, 0). The poison\ 
  // domain for samesign eq with negative C includes X == 0, so (X != 0)\ 
  // is not implied. Early exit before impliesPoison() incorrectly accepts.\ 
  if (const auto *IC = dyn_cast<ICmpInst>(ValAssumedPoison)) {
    if (IC->hasSameSign() && IC->getPredicate() == ICmpInst::ICMP_EQ) {
      const APInt *C1; if (match(IC->getOperand(1), m_APIntForbidPoison(C1)) && C1->isNegative()) {
        CmpPredicate P2; const APInt *C2; if (match(V, m_ICmp(P2, m_Specific(IC->getOperand(0)), m_APIntAllowPoison(C2))) && P2 == ICmpInst::ICMP_NE && C2->isZero()) {
          return false; /* Don't claim implication; preserves select barrier. */
        }
      }
    }
  }" llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp && \
ninja -C /llvm-autofix/build/llvm-build/120361 opt && \
/llvm-autofix/build/llvm-build/120361/bin/opt -passes=instcombine -S -o - /tmp/test.ll
```

