```bash
FILE=llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp && \
START=$(grep -n 'static bool impliesPoisonOrCond' "$FILE" | cut -d: -f1) && \
END=$(grep -n 'Instruction \*InstCombinerImpl::foldSelectOfBools' "$FILE" | cut -d: -f1) && END=$((END-1)) && \
awk -v s=$START -v e=$END 'NR==s {
print "static bool impliesPoisonOrCond(const Value *ValAssumedPoison, const Value *V,";
print "                                bool Expected) {";
print "  if (impliesPoison(ValAssumedPoison, V))";
print "    return true;";
print "";
print "  // PR120361: Guard against folding select (icmp ne X,0), (icmp samesign eq X,Cneg), false";
print "  // to a more poisonous form. When Cneg < 0, the poison domain for samesign eq includes";
print "  // X == 0, so (X != 0) is not implied; do not claim implication.";
print "  if (auto *IC = dyn_cast<ICmpInst>(ValAssumedPoison)) {";
print "    if (IC->hasSameSign() && IC->getPredicate() == ICmpInst::ICMP_EQ) {";
print "      const APInt *C1;";
print "      if (match(IC->getOperand(1), m_APIntForbidPoison(C1)) && C1->isNegative()) {";
print "        CmpPredicate P2; const APInt *C2;";
print "        if (match(V, m_ICmp(P2, m_Specific(IC->getOperand(0)), m_APIntAllowPoison(C2))) &&";
print "            P2 == ICmpInst::ICMP_NE && C2->isZero())";
print "          return false;";
print "      }";
print "    }";
print "  }";
print "";
print "  // Handle the case that ValAssumedPoison is `icmp samesign pred X, C1` and V";
print "  // is `icmp pred X, C2`, where C1 is well-defined.";
print "  if (auto *ICmp = dyn_cast<ICmpInst>(ValAssumedPoison)) {";
print "    Value *LHS = ICmp->getOperand(0);";
print "    const APInt *RHSC1;";
print "    const APInt *RHSC2;";
print "    CmpPredicate Pred;";
print "    if (ICmp->hasSameSign() &&";
print "        match(ICmp->getOperand(1), m_APIntForbidPoison(RHSC1)) &&";
print "        match(V, m_ICmp(Pred, m_Specific(LHS), m_APIntAllowPoison(RHSC2)))) {";
print "      // Extra guard for PR120361 inside ConstantRange reasoning.";
print "      if (Pred == ICmpInst::ICMP_NE && RHSC2->isZero() && RHSC1->isNegative())";
print "        return false;";
print "      unsigned BitWidth = RHSC1->getBitWidth();";
print "      ConstantRange CRX =";
print "          RHSC1->isNonNegative()";
print "              ? ConstantRange(APInt::getSignedMinValue(BitWidth),";
print "                              APInt::getZero(BitWidth))";
print "              : ConstantRange(APInt::getZero(BitWidth),";
print "                              APInt::getSignedMinValue(BitWidth));";
print "      return CRX.icmp(Expected ? Pred : ICmpInst::getInverseCmpPredicate(Pred),";
print "                      *RHSC2);";
print "    }";
print "  }";
print "";
print "  return false;";
print "}"; next
} NR>s && NR<=e {next} {print}' "$FILE" > /tmp/new && mv /tmp/new "$FILE" && \
ninja -C /llvm-autofix/build/llvm-build/120361 opt && \
/llvm-autofix/build/llvm-build/120361/bin/opt -passes=instcombine -S -o - /tmp/test.ll | sed -n '1,40p'
```

