THOUGHT: The KnownBits-based select elimination block got corrupted. I will replace the entire block (the comments and if statement) with a guarded version that only triggers when both select arms are constants, preserving the poison barrier (PR120361). Then rebuild opt and test the reproducer to ensure the select is retained.

```bash
FILE=llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp; \
START=$(grep -n '// If we can compute the condition' "$FILE" | cut -d: -f1); \
AFTER=$(grep -n 'if (Instruction \*BitCastSel = foldSelectCmpBitcasts' "$FILE" | cut -d: -f1); \
END=$((AFTER-1)); \
# Replace the block from START to END.
sed -i "${START},${END}c\  // If we can compute the condition, there's no need for a select.
  // PR120361: Do not eliminate the select if either arm is non-constant,
  // because the select forms a barrier preventing propagation of poison
  // from potentially poison-generating operands (e.g. samesign icmp).
  // Restrict this fold to the trivial constant-arm case.
  if (!CondVal->getType()->isVectorTy() && !AC.assumptions().empty() &&
      isa<Constant>(TrueVal) && isa<Constant>(FalseVal)) {
    KnownBits Known(1);
    computeKnownBits(CondVal, Known, 0, &SI);
    if (Known.One.isOne())
      return replaceInstUsesWith(SI, TrueVal);
    if (Known.Zero.isOne())
      return replaceInstUsesWith(SI, FalseVal);
  }" "$FILE"; \
# Build and test
ninja -C /llvm-autofix/build/llvm-build/120361 opt && \
/llvm-autofix/build/llvm-build/120361/bin/opt -passes=instcombine -S -o - /tmp/test.ll | sed -n '1,80p'
```

